def predict_wildfire(grid):
    import heapq

    if not grid or not grid[0]:
        return []

    rows, cols = len(grid), len(grid[0])
    dist = [[-1] * cols for _ in range(rows)]
    heap = []

    for r in range(rows):
        for c in range(cols):
            if grid[r][c] == '*':
                dist[r][c] = 0
                heapq.heappush(heap, (0, r, c))

    directions = [(0, 1), (0, -1), (1, 0), (-1, 0)]

    while heap:
        d, r, c = heapq.heappop(heap)
        if d > dist[r][c]:
            continue
        for dr, dc in directions:
            nr, nc = r + dr, c + dc
            if 0 <= nr < rows and 0 <= nc < cols:
                cell = grid[nr][nc]
                if cell == 'W' or cell == '*':
                    continue
                if cell == '.':
                    cost = 1
                elif cell == 'T':
                    cost = 2
                else:
                    continue
                new_dist = d + cost
                if dist[nr][nc] == -1 or new_dist < dist[nr][nc]:
                    dist[nr][nc] = new_dist
                    heapq.heappush(heap, (new_dist, nr, nc))

    return dist
